rule "fortigate timestamp"
when
    (has_field("tz") && has_field("date") && has_field("time")) 
then
    let build_message_0 = concat(to_string($message.date), " ");
    let build_message_1 = concat(build_message_0, to_string($message.time));
    let new_timestamp = parse_date(value:to_string(build_message_1), pattern:"yyyy-MM-dd HH:mm:sss", timezone:"America/Sao_Paulo");
    set_field("timestamp", new_timestamp);
end

rule "GeoIP Lookup:srcip"
when
 has_field("srcip")
then
 let geo = lookup("geoip", to_string($message.srcip));
 let geoasn = lookup("geoip-asn", to_string($message.srcip));
 set_field("srcgeolocation", geo["coordinates"]);
 set_field("srcgeocountry", geo["country"].iso_code);
 set_field("srcgeocity", geo["city"].names.en);
 set_field("srcasnnum", geoasn["as_number"]);
 set_field("srcasnname", geoasn["as_organization"]);
end

rule "GeoIP Lookup:remip"
when
