then
 let geo = lookup("geoip", to_string($message.remip));
 let geoasn = lookup("geoip-asn", to_string($message.remip));
 set_field("remgeolocation", geo["coordinates"]);
 set_field("remgeocountry", geo["country"].iso_code);
 set_field("remgeocity", geo["city"].names.en);
 set_field("remasnnum", geoasn["as_number"]);
 set_field("remasnname", geoasn["as_organization"]);
end

rule "GeoIP Lookup:dstip"
when
