then
 let geo = lookup("geoip", to_string($message.dstip));
 let geoasn = lookup("geoip-asn", to_string($message.dstip));
 set_field("dstgeolocation", geo["coordinates"]);
 set_field("dstgeocountry", geo["country"].iso_code);
 set_field("dstgeocity", geo["city"].names.en);
 set_field("dstasnnum", geoasn["as_number"]);
 set_field("dstasnname", geoasn["as_organization"]);
end

rule "fortigate-esp timestamp"
when
    (! has_field("tz") && has_field("date") && has_field("time")) 
then
    let build_message_0 = concat(to_string($message.date), " ");
    let build_message_1 = concat(build_message_0, to_string($message.time));
    let new_timestamp = parse_date(value:to_string(build_message_1), pattern:"yyyy-MM-dd HH:mm:sss", timezone:"America/Sao_Paulo");
    set_field("timestamp", new_timestamp);
    set_field("tz", "-0300");
end

